class TransactionEvent:
    """Represents a financial transaction event."""

    def __init__(self, data: Dict[str, Any]):
        self.transaction_id = data.get('transaction_id', '')
        self.event_type = data.get('event_type', '')
        self.amount = data.get('amount', 0.0)
        self.currency = data.get('currency', 'USD')
        self.sender_account = data.get('sender_account', '')
        self.receiver_account = data.get('receiver_account', '')
        self.timestamp = data.get('timestamp', datetime.utcnow().isoformat())
        self.metadata = data.get('metadata', {})
        self.status = data.get('status', 'pending')
        self.raw_data = data

    def __repr__(self):
        return (
            f"TransactionEvent(id={self.transaction_id}, type={self.event_type}, "
            f"amount={self.amount} {self.currency}, status={self.status})"
        )


class TransactionResult:
    """Result of processing a transaction event."""

    def __init__(self, transaction_id: str, success: bool, message: str = '',
                 details: Optional[Dict] = None):
        self.transaction_id = transaction_id
        self.success = success
        self.message = message
        self.details = details or {}
        self.processed_at = datetime.utcnow().isoformat()

    def __repr__(self):
        status = "SUCCESS" if self.success else "FAILED"
        return f"TransactionResult({self.transaction_id}: {status} - {self.message})"


class FraudDetectionService:
    """Simple fraud detection logic."""

    HIGH_AMOUNT_THRESHOLD = 10000.0
    SUSPICIOUS_COUNTRIES = {'XX', 'YY', 'ZZ'}

    @staticmethod
    def check_transaction(event: TransactionEvent) -> Dict[str, Any]:
        risk_score = 0.0
        flags = []

        if event.amount > FraudDetectionService.HIGH_AMOUNT_THRESHOLD:
            risk_score += 0.4
            flags.append('high_amount')

        country = event.metadata.get('country', '')
        if country in FraudDetectionService.SUSPICIOUS_COUNTRIES:
            risk_score += 0.5
            flags.append('suspicious_country')

        if event.metadata.get('is_international', False):
            risk_score += 0.1
            flags.append('international_transfer')

        if event.metadata.get('rapid_succession', False):
            risk_score += 0.3
            flags.append('rapid_succession')

        return {
            'risk_score': min(risk_score, 1.0),
            'flags': flags,
            'is_suspicious': risk_score >= 0.5,
            'requires_review': risk_score >= 0.3
        }


class ComplianceService:
    """AML and compliance checks."""

    @staticmethod
    def check_compliance(event: TransactionEvent) -> Dict[str, Any]:
        violations = []

        if event.amount > 50000 and not event.metadata.get('documentation_provided', False):
            violations.append('missing_documentation_large_transfer')

        if event.metadata.get('sanctioned_entity', False):
            violations.append('sanctioned_entity_involved')

        if not event.sender_account or not event.receiver_account:
            violations.append('incomplete_account_information')

        return {
            'compliant': len(violations) == 0,
            'violations': violations,
            'checked_at': datetime.utcnow().isoformat()
        }


class MessageHandlerRegistry:
    """Registry for dynamic message handlers."""

    def __init__(self):
        self._handlers: Dict[str, Callable[[TransactionEvent], TransactionResult]] = {}
        self._pre_processors: list = []
        self._post_processors: list = []

    def register_handler(self, event_type: str, handler: Callable):
        """Register a handler for a specific event type."""
        self._handlers[event_type] = handler
        logger.info(f"Registered handler for event type: {event_type}")

    def register_pre_processor(self, processor: Callable):
        """Register a pre-processor that runs before the main handler."""
        self._pre_processors.append(processor)

    def register_post_processor(self, processor: Callable):
        """Register a post-processor that runs after the main handler."""
        self._post_processors.append(processor)

    def get_handler(self, event_type: str) -> Optional[Callable]:
        return self._handlers.get(event_type)

    def get_pre_processors(self):
        return self._pre_processors

    def get_post_processors(self):
        return self._post_processors

    @property
    def registered_types(self):
        return list(self._handlers.keys())


class TransactionProcessor:
    """Core transaction processing engine."""

    def __init__(self):
        self.fraud_service = FraudDetectionService()
        self.compliance_service = ComplianceService()
        self.stats = {
            'processed': 0,
            'successful': 0,
            'failed': 0,
            'flagged': 0
        }

    def handle_deposit(self, event: TransactionEvent) -> TransactionResult:
        """Handle deposit transactions."""
        logger.info(f"Processing deposit: {event.transaction_id} - Amount: {event.amount} {event.currency}")

        fraud_check = self.fraud_service.check_transaction(event)
        if fraud_check['is_suspicious']:
            self.stats['flagged'] += 1
            return TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message='Transaction flagged for fraud review',
                details={'fraud_check': fraud_check}
            )

        compliance_check = self.compliance_service.check_compliance(event)
        if not compliance_check['compliant']:
            return TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message='Compliance check failed',
                details={'compliance_check': compliance_check}
            )

        return TransactionResult(
            transaction_id=event.transaction_id,
            success=True,
            message=f'Deposit of {event.amount} {event.currency} processed successfully',
            details={
                'fraud_check': fraud_check,
                'compliance_check': compliance_check,
                'credited_account': event.receiver_account
            }
        )

    def handle_withdrawal(self, event: TransactionEvent) -> TransactionResult:
        """Handle withdrawal transactions."""
        logger.info(f"Processing withdrawal: {event.transaction_id} - Amount: {event.amount} {event.currency}")

        fraud_check = self.fraud_service.check_transaction(event)
        if fraud_check['is_suspicious']:
            self.stats['flagged'] += 1
            return TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message='Withdrawal flagged for fraud review',
                details={'fraud_check': fraud_check}
            )

        # Simulate balance check
        available_balance = event.metadata.get('available_balance', float('inf'))
        if event.amount > available_balance:
            return TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message='Insufficient funds',
                details={'requested': event.amount, 'available': available_balance}
            )

        return TransactionResult(
            transaction_id=event.transaction_id,
            success=True,
            message=f'Withdrawal of {event.amount} {event.currency} processed successfully',
            details={
                'fraud_check': fraud_check,
                'debited_account': event.sender_account
            }
        )

    def handle_transfer(self, event: TransactionEvent) -> TransactionResult:
        """Handle transfer transactions between accounts."""
        logger.info(
            f"Processing transfer: {event.transaction_id} - "
            f"{event.sender_account} -> {event.receiver_account} - "
            f"Amount: {event.amount} {event.currency}"
        )

        fraud_check = self.fraud_service.check_transaction(event)
        compliance_check = self.compliance_service.check_compliance(event)

        if fraud_check['is_suspicious']:
            self.stats['flagged'] += 1
            return TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message='Transfer flagged for fraud review',
                details={'fraud_check': fraud_check, 'compliance_check': compliance_check}
            )

        if not compliance_check['compliant']:
            return TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message='Transfer failed compliance check',
                details={'compliance_check': compliance_check}
            )

        available_balance = event.metadata.get('available_balance', float('inf'))
        if event.amount > available_balance:
            return TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message='Insufficient funds for transfer',
                details={'requested': event.amount, 'available': available_balance}
            )

        return TransactionResult(
            transaction_id=event.transaction_id,
            success=True,
            message=f'Transfer of {event.amount} {event.currency} completed',
            details={
                'fraud_check': fraud_check,
                'compliance_check': compliance_check,
                'sender': event.sender_account,
                'receiver': event.receiver_account
            }
        )

    def handle_refund(self, event: TransactionEvent) -> TransactionResult:
        """Handle refund transactions."""
        logger.info(f"Processing refund: {event.transaction_id} - Amount: {event.amount} {event.currency}")

        original_transaction_id = event.metadata.get('original_transaction_id')
        if not original_transaction_id:
            return TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message='Refund requires original transaction ID',
                details={}
            )

        return TransactionResult(
            transaction_id=event.transaction_id,
            success=True,
            message=f'Refund of {event.amount} {event.currency} processed',
            details={
                'original_transaction_id': original_transaction_id,
                'refunded_to': event.receiver_account
            }
        )

    def handle_payment(self, event: TransactionEvent) -> TransactionResult:
        """Handle payment transactions."""
        logger.info(f"Processing payment: {event.transaction_id} - Amount: {event.amount} {event.currency}")

        fraud_check = self.fraud_service.check_transaction(event)
        compliance_check = self.compliance_service.check_compliance(event)

        if fraud_check['is_suspicious'] or not compliance_check['compliant']:
            self.stats['flagged'] += 1
            return TransactionResult(
                transaction_id=event.transaction_id,
                success=False,
                message='Payment blocked due to security concerns',
                details={'fraud_check': fraud_check, 'compliance_check': compliance_check}
            )

        return TransactionResult(
            transaction_id=event.transaction_id,
            success=True,
            message=f'Payment of {event.amount} {event.currency} processed',
            details={
                'fraud_check': fraud_check,
                'compliance_check': compliance_check,
                'merchant': event.metadata.get('merchant', 'unknown')
            }
        )

    def handle_chargeback(self, event: TransactionEvent) -> TransactionResult:
        """Handle chargeback events."""
        logger.info(f"Processing chargeback: {event.transaction_id}")

        original_transaction_id = event.metadata.get('original_transaction_id')
        reason = event.metadata.get('reason', 'unspecified')

        return TransactionResult(
            transaction_id=event.transaction_id,
            success=True,
            message=f'Chargeback initiated for reason: {reason}',
            details={
                'original_transaction_id': original_transaction_id,
                'reason': reason,
                'amount_reversed': event.amount
            }
        )

    def handle_unknown(self, event: TransactionEvent) -> TransactionResult:
        """Handle unknown transaction types."""
        logger.warning(f"Unknown event type: {event.event_type} for transaction {event.transaction_id}")
        return TransactionResult(
            transaction_id=event.transaction_id,
            success=False,
            message=f'Unknown event type: {event.event_type}',
            details={'raw_event_type': event.event_type}
        )


